function B4DUI.F4.BuildSidebar(side) local y=18; draw.NoTexture(); for _,tab in ipairs(B4DUI.Config.F4.Tabs) do if tab~="Admin" or B4DUI.HasPermission(LocalPlayer(),"admin_menu") then local b=B4DUI.UI.Button(side,tab,function() B4DUI.F4.ShowPage(tab) end); b:SetPos(14,y); b:SetSize(side:GetWide()-28,34); y=y+40 end end end
function B4DUI.F4.ShowPage(tab) local c=B4DUI.F4.Content; if not IsValid(c) then return end; c:Clear(); local l=B4DUI.UI.Label(c,"B4D "..tab,"B4D.Title"); l:SetPos(24,22); local d=B4DUI.UI.Label(c,"Premium clean-room module for "..tab..".","B4D.Body",B4DUI.Color("muted")); d:SetPos(24,58) end
